    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max in subarrays
    nums.sort((a, b) => a - b);

    let minRemovals = nums.length - 1; // Worst case: remove all but one

    // Try all possible subarrays of length >= 1
    for (let i = 0; i < nums.length; i++) {
        // Start of subarray
        let start = i;
        // End of subarray
        let end = nums.length - 1;

        // Try all possible subarrays starting at i
        while (start <= end) {
            // Current subarray is nums[start...end]
            let max = nums[end];
            let min = nums[start];

            // Check if the subarray is balanced
            if (max <= min * k) {
                // Calculate the number of elements to remove
                let removals = nums.length - (end - start + 1);
                minRemovals = Math.min(minRemovals, removals);
                break; // No need to check smaller subarrays
            }

            // Move the start pointer to the right
            start++;
        }
    }

    return minRemovals;
}

